import React from 'react';
import { BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';
import Home from './pages/Home';
import Services from './pages/Services';

function App() {
  return (
    <Router>
      <div className="App">
        {/* Navigation Bar */}
        <nav className="navbar navbar-expand-lg navbar-dark bg-dark sticky-top">
          <div className="container">
            <Link className="navbar-brand fw-bold" to="/">FreelanceMLA</Link>
            <div className="collapse navbar-collapse justify-content-end">
              <ul className="navbar-nav">
                <li className="nav-item">
                  <Link className="nav-link" to="/">Home</Link>
                </li>
                <li className="nav-item">
                  <Link className="nav-link" to="/services">My Services</Link>
                </li>
              </ul>
            </div>
          </div>
        </nav>

        {/* पेज बदलण्यासाठी Routes */}
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/services" element={<Services />} />
        </Routes>

        <footer className="bg-dark text-white py-4 text-center mt-5">
          <p>© 2024 Created by [Tumche Naav]</p>
        </footer>
      </div>
    </Router>
  );
}

export default App;
